// // This module implements a 4-bit down counter that decrements from 15 to 0. It resets to 15 when the reset signal is high.
module counter_4bit(
    input wire clk,
    input wire reset,
    output reg [3:0] count
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
